import { useMutation, UseMutationOptions } from '@tanstack/react-query'

import { client, gql } from '../client'
import { IMPRESORAFRAGMENT } from '../fragments/ImpresoraFragments'
import { Impresora, ImpresoraInput } from '../types'

export interface ImpresoraActualizarVariables {
  id: string
  input: ImpresoraInput
}

export const IMPRESORAACTUALIZAR = gql`
  mutation ImpresoraActualizar($id: ID!, $input: ImpresoraInput!) {
    impresoraActualizar(id: $id, input: $input) {
      ...ImpresoraFragment
    }
  }
  ${IMPRESORAFRAGMENT}
`

export const useImpresoraActualizar = (
  options?: UseMutationOptions<Impresora, Error, ImpresoraActualizarVariables>,
) => {
  return useMutation<Impresora, Error, ImpresoraActualizarVariables>({
    mutationFn: async (variables) => {
      const response = await client.request<{ impresoraActualizar: Impresora }>(
        IMPRESORAACTUALIZAR,
        variables,
      )
      return response.impresoraActualizar
    },
    ...options,
  })
}
